if (! function_exists('currency_exchange_rates')) {
    function currency_exchange_rates($from = null, $to = null, $amount = null, $timeout = null)
    {
        $from = strtoupper(trim($from ?? 'EUR'));
        $to = strtoupper(trim($to ?? 'USD'));
        $amount = (float)($amount ?? 1);
        $timeout = (int)($timeout ?? 15);

        if ($amount <= 0) {
            return ['success' => false, 'error' => 'Amount must be positive.'];
        }

        // frankfurter.dev — free, no API key, ECB exchange rates
        $url = 'https://api.frankfurter.dev/v1/latest'
            . '?from=' . urlencode($from)
            . '&to=' . urlencode($to)
            . '&amount=' . $amount;

        $context = stream_context_create([
            'http' => [
                'method' => 'GET',
                'timeout' => $timeout,
                'header' => "User-Agent: self-bootstrapping-agent/1.0\r\nAccept: application/json\r\n",
                'ignore_errors' => true,
                'follow_location' => 1,
                'max_redirects' => 5,
            ]
        ]);

        $response = @file_get_contents($url, false, $context);

        if ($response === false) {
            return ['success' => false, 'error' => 'Failed to reach exchange rate API.'];
        }

        // Capture HTTP status
        $status_code = 200;
        if (isset($http_response_header)) {
            foreach ($http_response_header as $h) {
                if (preg_match('#HTTP/\d\.\d\s+(\d+)#', $h, $m)) {
                    $status_code = (int)$m[1];
                    break;
                }
            }
        }

        $data = json_decode($response, true);

        if ($data === null) {
            return ['success' => false, 'error' => 'Failed to parse API response as JSON.', 'http_status' => $status_code];
        }

        if ($status_code !== 200 || !isset($data['rates'])) {
            $error_msg = $data['message'] ?? ('API returned status ' . $status_code);
            return ['success' => false, 'error' => $error_msg, 'http_status' => $status_code, 'raw_response' => mb_substr($response, 0, 500)];
        }

        $rates = $data['rates'];
        $results = [];
        foreach ($rates as $currency => $rate) {
            $converted = round((float)$rate, 4);
            $results[] = [
                'from' => $from,
                'to' => $currency,
                'rate' => (float)$rate,
                'amount_from' => $amount,
                'amount_to' => $converted,
            ];
        }

        // Inverse rates (how many units of target per 1 unit of base, and vice versa)
        $inverse = [];
        foreach ($rates as $currency => $rate) {
            $inv_rate = round(1.0 / (float)$rate, 6);
            $inverse[$currency] = [
                'rate' => $inv_rate,
                'description' => '1 ' . $currency . ' = ' . $inv_rate . ' ' . $from,
            ];
        }

        // Build readable conversions
        $conversions = array_map(function($r) {
            return $r['amount_from'] . ' ' . $r['from'] . ' = ' . $r['amount_to'] . ' ' . $r['to'];
        }, $results);

        return [
            'success' => true,
            'base' => $data['base'] ?? $from,
            'date' => $data['date'] ?? null,
            'amount' => $amount,
            'rates' => $results,
            'inverse_rates' => $inverse,
            'conversions' => $conversions,
        ];
    }
